function uuidv4() {
  if (globalThis.crypto && typeof crypto.randomUUID === 'function') return crypto.randomUUID();
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

function asArray(value) {
  if (Array.isArray(value)) return value;
  if (value == null) return [];
  return [value];
}

function normalizeEmail(value) {
  return String(value || '').trim().toLowerCase();
}

function statusFrom(value, fallback) {
  const status = String(value || fallback || 'active').toLowerCase();
  if (['active', 'pending', 'revoked'].includes(status)) return status;
  if (['disabled', 'deactivated', 'inactive', 'deleted'].includes(status)) return 'revoked';
  // Unknown status = least-privileged state, never a silent activation.
  return 'pending';
}

const root = $input.first().json || {};
let body = root.body || root;
// Replay payloads may carry the full webhook envelope ({headers,query,body}); unwrap it.
if (body && typeof body === 'object' && body.body && typeof body.body === 'object' && (body.headers || body.query || body.webhookUrl)) body = body.body;
const replay = !!root.replay;
const response_required = !!root.body && !replay;
const tenant_id = body.tenant_id || root.tenant_id || null;
const action = String(body.action || body.type || 'upsert').toLowerCase();
const validActions = ['upsert', 'revoke', 'sync', 'reconcile'];

const users = [];
for (const user of asArray(body.users)) {
  const email = normalizeEmail(user.email || user.user_email || user.userName || user.username);
  if (!email) continue;
  users.push({
    email,
    status: statusFrom(user.status, user.active === false ? 'revoked' : 'active'),
    last_seen: user.last_seen || user.lastSeen || null,
    source_id: user.id || user.externalId || null
  });
}

for (const resource of asArray(body.Resources || body.resources)) {
  const email = normalizeEmail(
    resource.userName ||
    resource.username ||
    resource.email ||
    (Array.isArray(resource.emails) && resource.emails[0] && resource.emails[0].value)
  );
  if (!email) continue;
  users.push({
    email,
    status: statusFrom(resource.status, resource.active === false ? 'revoked' : 'active'),
    last_seen: resource.last_seen || resource.lastSeen || null,
    source_id: resource.id || resource.externalId || null
  });
}

const singleEmail = normalizeEmail(body.email || body.user_email || body.userName);
if (singleEmail) {
  users.push({
    email: singleEmail,
    status: action === 'revoke' ? 'revoked' : statusFrom(body.status, body.active === false ? 'revoked' : 'active'),
    last_seen: body.last_seen || body.lastSeen || null,
    source_id: body.user_id || body.id || null
  });
}

const seen = new Set();
const normalizedUsers = [];
for (const user of users) {
  if (seen.has(user.email)) continue;
  seen.add(user.email);
  normalizedUsers.push(user);
}

const userKey = normalizedUsers.map((user) => user.email + ':' + user.status).sort().join('|') || 'empty';
// body.id/scim_id are RESOURCE ids — stable across a user's whole lifecycle. Used alone
// they would dedupe a later revocation against the original provision. Derived keys carry
// the roster+status hash AND a day bucket so recurring syncs re-run daily; only an explicit
// event_id keeps exact-once semantics.
const dayBucket = new Date().toISOString().slice(0, 10);
const sourceId = body.scim_id || (body.id && !body.event_id ? body.id : null);
const event_id = body.event_id || ((sourceId ? sourceId + ':' : '') + tenant_id + ':' + action + ':' + userKey + ':' + dayBucket);
const correlation_id = replay && root.correlation_id ? root.correlation_id : uuidv4();
const revoke_missing = body.revoke_missing != null ? !!body.revoke_missing : action === 'reconcile';
const stale_days = body.stale_days != null ? Number(body.stale_days) : null;
// An empty desired roster with revoke_missing would revoke EVERY seat in the tenant.
// Refuse unless the caller explicitly confirms that intent.
const empty_roster_revoke = revoke_missing && normalizedUsers.length === 0 && !body.confirm_empty_roster;
const invalid = !tenant_id || !validActions.includes(action) || ((action === 'upsert' || action === 'revoke' || action === 'sync') && normalizedUsers.length === 0) || empty_roster_revoke;

return [{ json: {
  tenant_id,
  action,
  users: normalizedUsers,
  event_id,
  idem_key: 'identity:' + event_id,
  replay,
  response_required,
  revoke_missing,
  stale_days: Number.isFinite(stale_days) && stale_days > 0 ? stale_days : null,
  invalid,
  invalid_reason: invalid ? (empty_roster_revoke ? 'refused: revoke_missing with an empty desired roster would revoke every seat in the tenant; pass confirm_empty_roster:true to proceed' : 'tenant_id, action=upsert|revoke|sync|reconcile, and at least one user for upsert/revoke/sync are required') : null,
  correlation_id,
  execution_id: String($execution.id),
  supabase_url: ($env.SUPABASE_URL || '').replace(/\/$/, '')
} }];

const p = $('Normalize Identity Event').first().json;
return [{ json: {
  tenant_id: p.tenant_id || null,
  correlation_id: p.correlation_id,
  service: 'identity',
  step: 'ingest',
  status: 'error',
  payload: { reason: p.invalid_reason, action: p.action, event_id: p.event_id, user_count: (p.users || []).length }
} }];

const p = $('Normalize Identity Event').first().json;
return [{ json: {
  tenant_id: p.tenant_id,
  correlation_id: p.correlation_id,
  service: 'identity',
  step: 'ingest',
  status: 'skipped',
  payload: { reason: 'duplicate event', key: p.idem_key, action: p.action, event_id: p.event_id }
} }];

const p = $('Normalize Identity Event').first().json;
const resolved = $('Resolve Policy').first().json || {};
return [{ json: {
  tenant_id: p.tenant_id,
  correlation_id: p.correlation_id,
  service: 'identity',
  step: 'sync',
  status: 'started',
  payload: {
    action: p.action,
    source: p.replay ? 'replay' : 'webhook',
    event_id: p.event_id,
    execution_id: p.execution_id,
    tenant_name: resolved.tenant_name || null,
    desired_user_count: (p.users || []).length,
    revoke_missing: p.revoke_missing,
    stale_days: p.stale_days
  }
} }];

const p = $('Normalize Identity Event').first().json;
const resolved = $('Resolve Policy').first().json || {};
const H = {
  apikey: $env.SUPABASE_SERVICE_KEY,
  Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_KEY,
  accept: 'application/json',
  'content-type': 'application/json'
};
const preferUpsert = Object.assign({}, H, { Prefer: 'resolution=merge-duplicates,return=representation' });
const preferPatch = Object.assign({}, H, { Prefer: 'return=representation' });
const helpers = this.helpers;

function enc(value) {
  return encodeURIComponent(String(value));
}
async function get(path) {
  return await helpers.httpRequest({ method: 'GET', url: p.supabase_url + path, headers: H, json: true });
}
// Paginated fetch: PostgREST caps responses (max-rows); missing a page here would
// mean seats silently escaping revocation.
async function getAll(path, pageSize = 1000) {
  const out = [];
  for (let from = 0; ; from += pageSize) {
    const page = await helpers.httpRequest({ method: 'GET', url: p.supabase_url + path, headers: Object.assign({}, H, { Range: from + '-' + (from + pageSize - 1), 'Range-Unit': 'items' }), json: true });
    if (!Array.isArray(page) || page.length === 0) break;
    out.push(...page);
    if (page.length < pageSize) break;
  }
  return out;
}
async function post(path, body) {
  return await helpers.httpRequest({ method: 'POST', url: p.supabase_url + path, headers: preferUpsert, body, json: true });
}
async function patch(path, body) {
  return await helpers.httpRequest({ method: 'PATCH', url: p.supabase_url + path, headers: preferPatch, body, json: true });
}

const tenantRows = await get('/rest/v1/tenants?id=eq.' + enc(p.tenant_id) + '&select=id,name,plan,region,status,health_score');
if (!tenantRows || tenantRows.length === 0) {
  throw new Error('identity: tenant not found: ' + p.tenant_id);
}
const tenant = tenantRows[0];
const beforeRows = await getAll('/rest/v1/seats?tenant_id=eq.' + enc(p.tenant_id) + '&select=id,user_email,status,last_seen,created_at');
const beforeByEmail = new Map((beforeRows || []).map((seat) => [String(seat.user_email || '').toLowerCase(), seat]));
const desiredEmails = new Set(p.users.map((user) => user.email));

let upserted = [];
if (p.users.length > 0) {
  // last_seen is activity telemetry — a sync asserting existence must not stamp it,
  // or stale-seat detection can never fire. Split batches so each bulk upsert has
  // uniform keys (PostgREST requirement).
  const toRow = (user, withSeen) => {
    const row = { tenant_id: p.tenant_id, user_email: user.email, status: p.action === 'revoke' ? 'revoked' : user.status };
    if (withSeen) row.last_seen = user.last_seen;
    return row;
  };
  const withSeen = p.users.filter((user) => user.last_seen);
  const withoutSeen = p.users.filter((user) => !user.last_seen);
  if (withSeen.length > 0) upserted = upserted.concat(await post('/rest/v1/seats?on_conflict=tenant_id,user_email', withSeen.map((user) => toRow(user, true))));
  if (withoutSeen.length > 0) upserted = upserted.concat(await post('/rest/v1/seats?on_conflict=tenant_id,user_email', withoutSeen.map((user) => toRow(user, false))));
}

let revokedMissing = [];
if ((p.action === 'sync' || p.action === 'reconcile') && p.revoke_missing) {
  const missing = (beforeRows || [])
    .filter((seat) => ['active', 'pending'].includes(seat.status))
    .filter((seat) => !desiredEmails.has(String(seat.user_email || '').toLowerCase()));
  const missingIds = missing.map((seat) => seat.id);
  for (let i = 0; i < missingIds.length; i += 100) {
    const changed = await patch('/rest/v1/seats?id=in.(' + missingIds.slice(i, i + 100).map(enc).join(',') + ')', { status: 'revoked' });
    revokedMissing.push(...(Array.isArray(changed) ? changed : [changed]));
  }
}

let revokedStale = [];
if (p.action === 'reconcile' && p.stale_days) {
  const cutoff = Date.now() - p.stale_days * 24 * 60 * 60 * 1000;
  const stale = (beforeRows || [])
    .filter((seat) => ['active', 'pending'].includes(seat.status))
    .filter((seat) => seat.last_seen && new Date(seat.last_seen).getTime() < cutoff)
    .filter((seat) => !revokedMissing.some((revoked) => revoked && revoked.id === seat.id));
  const staleIds = stale.map((seat) => seat.id);
  for (let i = 0; i < staleIds.length; i += 100) {
    const changed = await patch('/rest/v1/seats?id=in.(' + staleIds.slice(i, i + 100).map(enc).join(',') + ')', { status: 'revoked' });
    revokedStale.push(...(Array.isArray(changed) ? changed : [changed]));
  }
}

const afterRows = await getAll('/rest/v1/seats?tenant_id=eq.' + enc(p.tenant_id) + '&select=id,user_email,status,last_seen,created_at&order=user_email.asc');
const summary = {
  tenant_id: p.tenant_id,
  tenant_name: tenant.name,
  action: p.action,
  desired_user_count: p.users.length,
  before_count: (beforeRows || []).length,
  after_count: (afterRows || []).length,
  active_count: (afterRows || []).filter((seat) => seat.status === 'active').length,
  pending_count: (afterRows || []).filter((seat) => seat.status === 'pending').length,
  revoked_count: (afterRows || []).filter((seat) => seat.status === 'revoked').length,
  upserted_count: Array.isArray(upserted) ? upserted.length : 0,
  revoked_missing_count: revokedMissing.length,
  revoked_stale_count: revokedStale.length,
  entitlements: (resolved.policy && resolved.policy.entitlements) || {},
  completed_at: new Date().toISOString()
};

let telegram_delivered = false;
let notice = null;
const tgToken = $env.TELEGRAM_BOT_TOKEN || '';
const tgChat = $env.TELEGRAM_CHAT_ID || '';
if (tgToken && tgChat && (summary.revoked_missing_count > 0 || summary.revoked_stale_count > 0)) {
  const text = [
    'FlowOps identity lifecycle',
    'Tenant: ' + tenant.name,
    'Action: ' + p.action,
    'Upserted: ' + summary.upserted_count,
    'Revoked missing: ' + summary.revoked_missing_count,
    'Revoked stale: ' + summary.revoked_stale_count,
    'Correlation: ' + p.correlation_id
  ].join('\n');
  try {
    await helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot' + tgToken + '/sendMessage',
      body: { chat_id: tgChat, text },
      json: true
    });
    telegram_delivered = true;
  } catch (e) {
    notice = 'telegram failed: ' + (e && e.message ? e.message : String(e));
  }
} else if (!tgToken || !tgChat) {
  notice = 'telegram skipped: TELEGRAM_BOT_TOKEN / TELEGRAM_CHAT_ID not set';
} else {
  notice = 'telegram skipped: no revocations';
}

return [{ json: {
  tenant_id: p.tenant_id,
  correlation_id: p.correlation_id,
  event_id: p.event_id,
  summary,
  changed_users: {
    upserted: Array.isArray(upserted) ? upserted.map((seat) => ({ email: seat.user_email, status: seat.status })) : [],
    revoked_missing: revokedMissing.map((seat) => ({ email: seat.user_email, status: seat.status })),
    revoked_stale: revokedStale.map((seat) => ({ email: seat.user_email, status: seat.status }))
  },
  telegram_delivered,
  notice
} }];

const r = $('Reconcile Seats').first().json;
return [{ json: {
  tenant_id: r.tenant_id,
  correlation_id: r.correlation_id,
  service: 'identity',
  step: 'reconcile-seats',
  status: 'success',
  payload: {
    event_id: r.event_id,
    summary: r.summary,
    changed_users: r.changed_users,
    telegram_delivered: r.telegram_delivered,
    notice: r.notice
  }
} }];
